"""
Parameterized generator for GH1183_mlflow_21797.

Source PR:    https://github.com/mlflow/mlflow/pull/21797
Source Issue: N/A

Seed varies: renames 'assert_called_once' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH1183_mlflow_21797'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH1183_mlflow_21797'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('assert_called_once', 'assert_called_once' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH1183_mlflow_21797',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'mlflow/mlflow',
                "pr_number": 21797,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/mlflow/mlflow/pull/21797",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'mlflow/server/jobs/utils.py': 'import errno\nimport hashlib\nimport importlib\nimport inspect\nimport json\nimport logging\nimport os\nimport shutil\nimport signal\nimport subprocess\nimport sys\nimport tempfile\nimport threading\nimport time\nfrom contextlib import nullcontext\nfrom dataclasses import asdict, dataclass\nfrom datetime import datetime\nfrom pathlib import Path\nfrom typing import TYPE_CHECKING, Any, Callable, ContextManager\n\nfrom mlflow.entities._job_status import JobStatus\nfrom mlflow.environment_variables import (\n    MLFLOW_ENABLE_WORKSPACES,\n    MLFLOW_LOGGING_LEVEL,\n    MLFLOW_SERVER_JOB_TRANSIENT_ERROR_RETRY_BASE_DELAY,\n    MLFLOW_SERVER_JOB_TRANSIENT_ERROR_RETRY_MAX_DELAY,\n    MLFLOW_WORKSPACE,\n)\nfrom mlflow.exceptions import MlflowException\nfrom mlflow.server.constants import HUEY_STORAGE_PATH_ENV_VAR\nfrom mlflow.utils.environment import _PythonEnv\nfrom mlflow.utils.import_hooks import register_post_import_hook\nfrom mlflow.utils.process import _exec_cmd\nfrom mlflow.utils.workspace_context import WorkspaceContext\nfrom mlflow.utils.workspace_utils import DEFAULT_WORKSPACE_NAME\n\nif TYPE_CHECKING:\n    import huey\n\n    from mlflow.store.jobs.abstract_store import AbstractJobStore\n\n_logger = logging.getLogger(__name__)\n\n# Reserved Huey instance key for periodic tasks\nHUEY_PERIODIC_TASKS_INSTANCE_KEY = "periodic_tasks"\n\n# Environment variable name for the job name set in job subprocesses\nMLFLOW_SERVER_JOB_NAME_ENV_VAR = "_MLFLOW_SERVER_JOB_NAME"\n\n# Number of worker threads for the periodic tasks consumer\nPERIODIC_TASKS_WORKER_COUNT = 5\n\n\ndef _exponential_backoff_retry(retry_count: int) -> None:\n    from huey.exceptions import RetryTask\n\n    # We can support more retry strategies (e.g. exponential backoff) in future\n    base_delay = MLFLOW_SERVER_JOB_TRANSIENT_ERROR_RETRY_BASE_DELAY.get()\n    max_delay = MLFLOW_SERVER_JOB_TRANSIENT_ERROR_RETRY_MAX_DELAY.get()\n    delay = min(base_delay * (2 ** (retry_count - 1)), max_delay)\n    raise RetryTask(delay=delay)\n\n\n@dataclass\nclass JobResult:\n    succeeded: bool\n    result: str | None = None  # serialized JSON string\n    is_transient_error: bool | None = None\n    error: str | None = None\n\n    @classmethod\n    def from_error(\n        cls, e: Exception, transient_error_classes: list[type[Exception]] | None = None\n    ) -> "JobResult":\n        from mlflow.server.jobs import TransientError\n\n        if isinstance(e, TransientError):\n            return JobResult(succeeded=False, is_transient_error=True, error=repr(e.origin_error))\n\n        if transient_error_classes:\n            if e.__class__ in transient_error_classes:\n                return JobResult(succeeded=False, is_transient_error=True, error=repr(e))\n\n        return JobResult(\n            succeeded=False,\n            is_transient_error=False,\n            error=repr(e),\n        )\n\n    def dump(self, path: str) -> None:\n        with open(path, "w") as fp:\n            json.dump(asdict(self), fp)\n\n    @classmethod\n    def load(cls, path: str) -> "JobResult":\n        with open(path) as fp:\n            return JobResult(**json.load(fp))\n\n\ndef _exit_when_orphaned(poll_interval: float = 1) -> None:\n    while True:\n        if os.getppid() == 1:\n            os._exit(1)\n        time.sleep(poll_interval)\n\n\ndef is_process_alive(pid: int) -> bool:\n    if pid <= 0:\n        return False\n    try:\n        os.kill(pid, 0)  # doesn\'t actually kill\n    except OSError as e:\n        if e.errno == errno.ESRCH:  # No such process\n            return False\n        elif e.errno == errno.EPERM:  # Process exists, but no permission\n            return True\n        else:\n            raise\n    else:\n        return True\n\n\ndef _start_huey_consumer_proc(\n    huey_instance_key: str,\n    max_job_parallelism: int,\n):\n    from mlflow.server.constants import MLFLOW_HUEY_INSTANCE_KEY\n    from mlflow.utils.process import _exec_cmd\n\n    cmd = [\n        sys.executable,\n        shutil.which("huey_consumer.py"),\n        "mlflow.server.jobs._huey_consumer.huey_instance",\n        "-w",\n        str(max_job_parallelism),\n    ]\n\n    # Add quiet flag unless DEBUG logging is explicitly requested,\n    # to suppress noisy huey consumer logs (e.g., Scheduler, Executing messages)\n    log_level = (MLFLOW_LOGGING_LEVEL.get() or "INFO").upper()\n    if log_level != "DEBUG":\n        cmd.append("-q")\n\n    return _exec_cmd(\n        cmd,\n        capture_output=False,\n        synchronous=False,\n        extra_env={\n            MLFLOW_HUEY_INSTANCE_KEY: huey_instance_key,\n        },\n    )\n\n\n_JOB_ENTRY_MODULE = "mlflow.server.jobs._job_subproc_entry"\n\n\n_JOB_STATUS_POLL_INTERVAL = 1\n\n\ndef _exec_job_in_subproc(\n    function_fullname: str,\n    params: dict[str, Any],\n    python_env: _PythonEnv | None,\n    transient_error_classes: list[type[Exception]] | None,\n    timeout: float | None,\n    tmpdir: str,\n    job_store: "AbstractJobStore",\n    job_id: str,\n    job_name: str,\n    workspace: str | None,\n    extra_envs: dict[str, str] | None = None,\n) -> JobResult | None:\n    """\n    Executes the job function in a subprocess,\n    If the job execution time exceeds timeout, the subprocess is killed and return None,\n    otherwise return `JobResult` instance,\n    """\n    from mlflow.utils.process import _exec_cmd, _join_commands\n    from mlflow.utils.virtualenv import (\n        _get_mlflow_virtualenv_root,\n        _get_uv_env_creation_command,\n        _get_virtualenv_activate_cmd,\n        _get_virtualenv_extra_env_vars,\n        _get_virtualenv_name,\n    )\n\n    if python_env is not None:\n        if shutil.which("uv") is None:\n            raise MlflowException(\n                "The job requires \'uv\' to create an isolated Python environment, "\n                "but \'uv\' is not installed."\n            )\n\n        # set up virtual python environment\n        virtual_envs_root_path = Path(_get_mlflow_virtualenv_root())\n        env_name = _get_virtualenv_name(python_env, None)\n        env_dir = virtual_envs_root_path / env_name\n        activate_cmd = _get_virtualenv_activate_cmd(env_dir)\n\n        if not env_dir.exists():\n            _logger.info(f"Creating a python virtual environment in {env_dir}.")\n            # create python environment\n            env_creation_cmd = _get_uv_env_creation_command(env_dir, python_env.python)\n            _exec_cmd(env_creation_cmd, capture_output=False)\n\n            # install dependencies\n            tmp_req_file = "requirements.txt"\n            (Path(tmpdir) / tmp_req_file).write_text("\\n".join(python_env.dependencies))\n            cmd = _join_commands(activate_cmd, f"uv pip install -r {tmp_req_file}")\n            _exec_cmd(\n                cmd,\n                cwd=tmpdir,\n                extra_env=_get_virtualenv_extra_env_vars(),\n                capture_output=False,\n            )\n        else:\n            _logger.debug(f"The python environment {env_dir} already exists.")\n\n        job_cmd = _join_commands(activate_cmd, f"exec python -m {_JOB_ENTRY_MODULE}")\n    else:\n        job_cmd = [sys.executable, "-m", _JOB_ENTRY_MODULE]\n\n    result_file = str(Path(tmpdir) / "result.json")\n    transient_error_classes_file = str(Path(tmpdir) / "transient_error_classes")\n    transient_error_classes = transient_error_classes or []\n    with open(transient_error_classes_file, "w") as f:\n        for cls in transient_error_classes:\n            f.write(f"{cls.__module__}.{cls.__name__}\\n")\n\n    job_env = {\n        **os.environ,\n        MLFLOW_SERVER_JOB_NAME_ENV_VAR: job_name,\n        "_MLFLOW_SERVER_JOB_PARAMS": json.dumps(params),\n        "_MLFLOW_SERVER_JOB_FUNCTION_FULLNAME": function_fullname,\n        "_MLFLOW_SERVER_JOB_RESULT_DUMP_PATH": result_file,\n        "_MLFLOW_SERVER_JOB_TRANSIENT_ERROR_ClASSES_PATH": transient_error_classes_file,\n        **(extra_envs or {}),\n    }\n\n    if workspace:\n        job_env[MLFLOW_WORKSPACE.name] = workspace\n\n    with subprocess.Popen(\n        job_cmd,\n        env=job_env,\n    ) as popen:\n        beg_time = time.time()\n        while popen.poll() is None:\n            time.sleep(_JOB_STATUS_POLL_INTERVAL)\n\n            job_status = job_store.get_job(job_id).status\n            if job_status == JobStatus.CANCELED:\n                popen.kill()\n                return None\n\n            if timeout is not None:\n                if beg_time + timeout <= time.time():\n                    # timeout\n                    popen.kill()\n                    job_store.mark_job_timed_out(job_id)\n                    return None\n\n        if popen.returncode == 0:\n            return JobResult.load(result_file)\n\n        return JobResult.from_error(\n            RuntimeError(\n                f"The subprocess that executes job function {function_fullname} "\n                f"exists with error code {popen.returncode}"\n            )\n        )\n\n\ndef _compute_exclusive_lock_key(job_name: str, params: dict[str, Any]) -> str:\n    """\n    Compute a lock key based on job name and params hash.\n\n    Args:\n        job_name: Name of the job.\n        params: Parameter dictionary to use for the lock key.\n\n    Returns:\n        Lock key string.\n    """\n    params_json = json.dumps(params, sort_keys=True)\n    params_hash = hashlib.sha256(params_json.encode()).hexdigest()[:16]\n    return f"{job_name}:{params_hash}"\n\n\ndef _exec_job(\n    job_id: str,\n    workspace: str | None,\n    job_name: str,\n    params: dict[str, Any],\n    timeout: float | None,\n    exclusive: bool | list[str] = False,\n    extra_envs: dict[str, str] | None = None,\n) -> None:\n    """\n    Execute a job in a subprocess.\n\n    Args:\n        job_id: Unique identifier for the job.\n        workspace: Workspace associated with the job.\n        job_name: Name of the job function to execute.\n        params: Parameters to pass to the job function.\n        timeout: Maximum execution time in seconds, or None for no timeout.\n        exclusive: If True, only one instance of this job with the same params can run\n            at a time. If a list of parameter names, only those parameters are considered\n            for exclusivity.\n        extra_envs: Optional dictionary of additional environment variables to set\n            before executing the job.\n    """\n    from mlflow.server.handlers import _get_job_store\n\n    workspace_ctx = WorkspaceContext(workspace) if workspace else nullcontext()\n    with workspace_ctx:\n        job_store = _get_job_store()\n\n        # If exclusive, acquire lock based on job_name + hash(params)\n        # If lock is already held, TaskLockedException is raised and job is skipped\n        lock = None\n        if exclusive:\n            from huey.exceptions import TaskLockedException\n\n            huey_instance = _get_or_init_huey_instance(job_name).instance\n            # If exclusive is a list, filter params to only those specified\n            lock_params = (\n                {k: v for k, v in params.items() if k in exclusive}\n                if isinstance(exclusive, list)\n                else params\n            )\n\n            lock_key_job_name = job_name\n            if MLFLOW_ENABLE_WORKSPACES.get():\n                lock_key_job_name = f"{workspace or DEFAULT_WORKSPACE_NAME}:{job_name}"\n            lock_key = _compute_exclusive_lock_key(lock_key_job_name, lock_params)\n            lock = huey_instance.lock_task(lock_key)\n            try:\n                lock.acquire()\n            except TaskLockedException:\n                _logger.info(f"Skipping job {job_id} - exclusive lock {lock_key} already held")\n                job_store.cancel_job(job_id)\n                return\n        else:\n            lock = None\n\n        try:\n            job_store.start_job(job_id)\n\n            fn_fullname = get_job_fn_fullname(job_name)\n            function = _load_function(fn_fullname)\n            fn_metadata = function._job_fn_metadata\n\n            with tempfile.TemporaryDirectory() as tmpdir:\n                job_result = _exec_job_in_subproc(\n                    fn_metadata.fn_fullname,\n                    params,\n                    fn_metadata.python_env,\n                    fn_metadata.transient_error_classes,\n                    timeout,\n                    tmpdir,\n                    job_store,\n                    job_id,\n                    job_name,\n                    workspace,\n                    extra_envs,\n                )\n\n            if job_result is None:\n                return\n\n            if job_result.succeeded:\n                job_store.finish_job(job_id, job_result.result)\n                return\n\n            if job_result.is_transient_error:\n                # For transient errors, if the retry count is less than max allowed count,\n                # trigger task retry by raising `RetryTask` exception.\n                retry_count = job_store.retry_or_fail_job(job_id, job_result.error)\n                if retry_count is not None:\n                    _exponential_backoff_retry(retry_count)\n            else:\n                _logger.error(f"Job {job_id} ({job_name}) failed with error: {job_result.error}")\n                job_store.fail_job(job_id, job_result.error)\n        finally:\n            if lock is not None:\n                lock.release()\n\n\n@dataclass\nclass HueyInstance:\n    instance: "huey.SqliteHuey"\n    submit_task: Callable[..., Any]\n\n\n# Each job function has an individual execution pool, each execution pool\n# is managed by a Huey instance.\n# The `_huey_instance_map` stores the map, the key is the job function fullname,\n# and the value is the `HueyInstance` object.\n_huey_instance_map: dict[str, HueyInstance] = {}\n_huey_instance_map_lock = threading.RLock()\n\n\ndef _get_or_init_huey_instance(instance_key: str):\n    from huey import SqliteHuey\n    from huey.serializer import Serializer\n\n    class CustomJSONEncoder(json.JSONEncoder):\n        def default(self, obj):\n            if isinstance(obj, datetime):\n                return {\n                    "__type__": "datetime",\n                    "value": obj.isoformat(),\n                }\n            return super().default(obj)\n\n    def json_loader_object_hook(d):\n        if d.get("__type__") == "datetime":\n            return datetime.fromisoformat(d["value"])\n        return d\n\n    class JsonSerializer(Serializer):\n        def serialize(self, data):\n            # Huey passes two types of data through the serializer:\n            # 1. Message objects (task data) - have ._asdict() method\n            # 2. Plain data (e.g., lock values like \'1\') - no ._asdict() method\n            # We need to handle both cases for exclusive job locks to work.\n            data_dict = data._asdict() if hasattr(data, "_asdict") else data\n            return json.dumps(data_dict, cls=CustomJSONEncoder).encode("utf-8")\n\n        def deserialize(self, data):\n            from huey.registry import Message\n\n            decoded = json.loads(data.decode("utf-8"), object_hook=json_loader_object_hook)\n            # Message objects have specific structure: {"id": ..., "name": ..., ...}\n            # Only reconstruct as Message when that structure exists.\n            # Plain data (like lock values) should be returned as-is.\n            if isinstance(decoded, dict) and "id" in decoded and "name" in decoded:\n                return Message(**decoded)\n            else:\n                return decoded\n\n    with _huey_instance_map_lock:\n        if instance_key not in _huey_instance_map:\n            _logger.debug(f"Creating huey instance for {instance_key}")\n            huey_store_file = os.path.join(\n                os.environ[HUEY_STORAGE_PATH_ENV_VAR], f"{instance_key}.mlflow-huey-store"\n            )\n            huey_instance = SqliteHuey(\n                filename=huey_store_file,\n                results=False,\n                serializer=JsonSerializer(),\n            )\n            huey_submit_task_fn = huey_instance.task(retries=0)(_exec_job)\n            _huey_instance_map[instance_key] = HueyInstance(\n                instance=huey_instance,\n                submit_task=huey_submit_task_fn,\n            )\n        return _huey_instance_map[instance_key]\n\n\ndef _launch_huey_consumer(job_name: str) -> None:\n    _logger.debug(f"Starting huey consumer for job function {job_name}")\n\n    fn_fullname = get_job_fn_fullname(job_name)\n    job_fn = _load_function(fn_fullname)\n\n    if not hasattr(job_fn, "_job_fn_metadata"):\n        raise MlflowException.invalid_parameter_value(\n            f"The job function {job_name} is not decorated by \'mlflow.server.jobs.job_function\'."\n        )\n\n    max_job_parallelism = job_fn._job_fn_metadata.max_workers\n\n    def _huey_consumer_thread() -> None:\n        while True:\n            # start MLflow job runner process\n            # Put it inside the loop to ensure the job runner process alive\n            job_runner_proc = _start_huey_consumer_proc(\n                job_name,\n                max_job_parallelism,\n            )\n            job_runner_proc.wait()\n            time.sleep(1)\n\n    # start job runner.\n    threading.Thread(\n        target=_huey_consumer_thread,\n        name=f"MLflow-huey-consumer-{job_name}-watcher",\n        daemon=False,\n    ).start()\n\n\ndef _launch_periodic_tasks_consumer() -> None:\n    """\n    Launch a dedicated Huey consumer for periodic tasks.\n    This consumer runs scheduled tasks like the online scoring scheduler.\n    """\n    _logger.debug("Starting dedicated Huey consumer for periodic tasks")\n\n    def _huey_consumer_thread() -> None:\n        while True:\n            job_runner_proc = _start_periodic_tasks_consumer_proc()\n            job_runner_proc.wait()\n            time.sleep(1)\n\n    threading.Thread(\n        target=_huey_consumer_thread,\n        name="MLflow-huey-consumer-periodic-tasks-watcher",\n        daemon=False,\n    ).start()\n\n\ndef _start_periodic_tasks_consumer_proc():\n    cmd = [\n        sys.executable,\n        shutil.which("huey_consumer.py"),\n        "mlflow.server.jobs._periodic_tasks_consumer.huey_instance",\n        "-w",\n        str(PERIODIC_TASKS_WORKER_COUNT),\n    ]\n\n    # Add quiet flag unless DEBUG logging is explicitly requested,\n    # to suppress noisy huey consumer logs (e.g., Scheduler, Executing messages)\n    log_level = (MLFLOW_LOGGING_LEVEL.get() or "INFO").upper()\n    if log_level != "DEBUG":\n        cmd.append("-q")\n\n    return _exec_cmd(\n        cmd,\n        capture_output=False,\n        synchronous=False,\n    )\n\n\ndef _launch_job_runner(env_map, server_proc_pid):\n    return subprocess.Popen(\n        [\n            sys.executable,\n            "-m",\n            "mlflow.server.jobs._job_runner",\n        ],\n        env={**os.environ, **env_map, "MLFLOW_SERVER_PID": str(server_proc_pid)},\n    )\n\n\ndef _start_watcher_to_kill_job_runner_if_mlflow_server_dies(check_interval: float = 1.0) -> None:\n    mlflow_server_pid = int(os.environ.get("MLFLOW_SERVER_PID"))\n\n    def watcher():\n        while True:\n            if not is_process_alive(mlflow_server_pid):\n                os.kill(os.getpid(), signal.SIGTERM)\n            time.sleep(check_interval)\n\n    t = threading.Thread(target=watcher, daemon=True, name="job-runner-watcher")\n    t.start()\n\n\ndef _load_function(fullname: str) -> Callable[..., Any]:\n    match fullname.split("."):\n        case [*module_parts, func_name] if module_parts:\n            module_name = ".".join(module_parts)\n        case _:\n            raise MlflowException.invalid_parameter_value(\n                f"Invalid function fullname format: {fullname}"\n            )\n    try:\n        module = importlib.import_module(module_name)\n        return getattr(module, func_name)\n    except ModuleNotFoundError:\n        # Module doesn\'t exist\n        raise MlflowException.invalid_parameter_value(\n            f"Module not found for function \'{fullname}\'",\n        )\n    except AttributeError:\n        # Function doesn\'t exist in the module\n        raise MlflowException.invalid_parameter_value(\n            f"Function not found in module for \'{fullname}\'",\n        )\n\n\ndef _workspace_contexts_for_recovery() -> list[ContextManager[str | None]]:\n    """\n    Determine the set of workspace contexts that may contain unfinished jobs.\n\n    When workspaces are disabled, this returns only a ``nullcontext``. Otherwise, it queries the\n    configured workspace store to enumerate all defined workspaces so the job runner can resume\n    tasks for each tenant.\n    """\n    if not MLFLOW_ENABLE_WORKSPACES.get():\n        return [nullcontext()]\n\n    from mlflow.server.workspace_helpers import _get_workspace_store  # avoid circular import\n\n    store = _get_workspace_store()\n    return [WorkspaceContext(workspace.name) for workspace in store.list_workspaces()]\n\n\ndef _enqueue_unfinished_jobs(server_launching_timestamp: int) -> None:\n    from mlflow.server.handlers import _get_job_store\n\n    job_store = _get_job_store()\n\n    for workspace_ctx in _workspace_contexts_for_recovery():\n        with workspace_ctx as workspace:\n            unfinished_jobs = job_store.list_jobs(\n                statuses=[JobStatus.PENDING, JobStatus.RUNNING],\n                # filter out jobs created after the server is launched.\n                end_timestamp=server_launching_timestamp,\n            )\n\n            for job in unfinished_jobs:\n                if job.status == JobStatus.RUNNING:\n                    job_store.reset_job(job.job_id)  # reset the job status to PENDING\n\n                params = json.loads(job.params)\n                timeout = job.timeout\n                job_workspace = job.workspace or workspace or DEFAULT_WORKSPACE_NAME\n                # Look up exclusive flag from function metadata\n                fn_fullname = get_job_fn_fullname(job.job_name)\n                fn_metadata = _load_function(fn_fullname)._job_fn_metadata\n                # enqueue job\n                _get_or_init_huey_instance(job.job_name).submit_task(\n                    job.job_id,\n                    job_workspace,\n                    job.job_name,\n                    params,\n                    timeout,\n                    fn_metadata.exclusive,\n                )\n\n\ndef _validate_function_parameters(function: Callable[..., Any], params: dict[str, Any]) -> None:\n    """Validate that the provided parameters match the function\'s required arguments.\n\n    Args:\n        function: The function to validate parameters against\n        params: Dictionary of parameters provided for the function\n\n    Raises:\n        MlflowException: If required parameters are missing\n    """\n    sig = inspect.signature(function)\n\n    # Get all required parameters (no default value)\n    # Exclude VAR_POSITIONAL (*args) and VAR_KEYWORD (**kwargs) parameters\n    required_params = [\n        name\n        for name, param in sig.parameters.items()\n        if param.default is inspect.Parameter.empty\n        and param.kind not in (inspect.Parameter.VAR_POSITIONAL, inspect.Parameter.VAR_KEYWORD)\n    ]\n\n    # Check for missing required parameters\n    if missing_params := [param for param in required_params if param not in params]:\n        raise MlflowException.invalid_parameter_value(\n            f"Missing required parameters for function \'{function.__name__}\': {missing_params}. "\n            f"Expected parameters: {list(sig.parameters.keys())}"\n        )\n\n\ndef _check_requirements(backend_store_uri: str | None = None) -> None:\n    from mlflow.server.constants import BACKEND_STORE_URI_ENV_VAR\n    from mlflow.utils.uri import extract_db_type_from_uri\n\n    if os.name == "nt":\n        raise MlflowException("MLflow job backend does not support Windows system.")\n\n    backend_store_uri = backend_store_uri or os.environ.get(BACKEND_STORE_URI_ENV_VAR)\n    if not backend_store_uri:\n        raise MlflowException(\n            "MLflow job backend requires a database backend store URI but "\n            "\'--backend-store-uri\' is not set"\n        )\n    try:\n        extract_db_type_from_uri(backend_store_uri)\n    except MlflowException:\n        raise MlflowException(\n            f"MLflow job backend requires a database backend store URI but got {backend_store_uri}"\n        )\n\n\n# The map from job name to the job function\'s fullname.\n_job_name_to_fn_fullname_map = {}\n\n\ndef get_job_fn_fullname(job_name: str):\n    if job_name not in _job_name_to_fn_fullname_map:\n        raise MlflowException.invalid_parameter_value(f"Invalid job name: {job_name}")\n    return _job_name_to_fn_fullname_map[job_name]\n\n\ndef _build_job_name_to_fn_fullname_map():\n    from mlflow.server.jobs import _SUPPORTED_JOB_FUNCTION_LIST\n\n    for fn_fullname in set(_SUPPORTED_JOB_FUNCTION_LIST):\n        try:\n            fn_meta = _load_function(fn_fullname)._job_fn_metadata\n            if exist_fullname := _job_name_to_fn_fullname_map.get(fn_meta.name):\n                if exist_fullname != fn_fullname:\n                    _logger.warning(\n                        f"The 2 job functions {fn_fullname} and {exist_fullname} have the same "\n                        f"job name {fn_meta.name}, this is not allowed, skip loading function "\n                        f"{fn_fullname}."\n                    )\n            else:\n                _job_name_to_fn_fullname_map[fn_meta.name] = fn_fullname\n        except Exception as e:\n            _logger.warning(f"loading job function {fn_fullname} failed: {e!r}", exc_info=True)\n\n\nregister_post_import_hook(lambda m: _build_job_name_to_fn_fullname_map(), __name__)\n\n\ndef register_periodic_tasks(huey_instance) -> None:\n    """\n    Register all periodic tasks with the given huey instance.\n\n    Args:\n        huey_instance: The huey instance to register tasks with.\n    """\n    from huey import crontab\n\n    @huey_instance.periodic_task(crontab(minute="*/1"))\n    # Prevent concurrent execution if scheduler takes longer than 1 minute.\n    @huey_instance.lock_task("online-scoring-scheduler-lock")\n    def online_scoring_scheduler():\n        """Runs every minute to fetch active scorer configs and submit scoring jobs."""\n        from mlflow.genai.scorers.job import run_online_scoring_scheduler\n\n        try:\n            run_online_scoring_scheduler()\n        except Exception as e:\n            _logger.exception(f"Online scoring scheduler failed: {e!r}")\n\n    _logger.info("Registered online_scoring_scheduler periodic task (runs every 1 minute)")\n',
            'tests/server/jobs/test_jobs.py': 'import concurrent.futures\nimport multiprocessing\nimport os\nimport time\nfrom pathlib import Path\n\nimport pytest\n\nfrom mlflow.entities._job_status import JobStatus\nfrom mlflow.environment_variables import MLFLOW_ENABLE_WORKSPACES, MLFLOW_WORKSPACE\nfrom mlflow.exceptions import MlflowException\nfrom mlflow.server.handlers import _get_job_store\nfrom mlflow.server.jobs import (\n    TransientError,\n    cancel_job,\n    get_job,\n    job,\n    submit_job,\n)\nfrom mlflow.store.jobs.sqlalchemy_store import SqlAlchemyJobStore\nfrom mlflow.store.jobs.sqlalchemy_workspace_store import WorkspaceAwareSqlAlchemyJobStore\nfrom mlflow.utils.workspace_context import WorkspaceContext\nfrom mlflow.utils.workspace_utils import DEFAULT_WORKSPACE_NAME\n\nfrom tests.server.jobs.helpers import (\n    _get_mlflow_repo_home,\n    _launch_job_runner_for_test,\n    _setup_job_runner,\n    wait_for_process_exit,\n    wait_job_finalize,\n)\n\n# TODO: Remove `pytest.mark.xfail` after fixing flakiness\npytestmark = [\n    pytest.mark.skipif(os.name == "nt", reason="MLflow job execution is not supported on Windows"),\n]\n\n\n@pytest.fixture(autouse=True, params=[False, True], ids=["workspace-disabled", "workspace-enabled"])\ndef workspaces_enabled(request, monkeypatch):\n    """\n    Run every test in this module with workspaces disabled and enabled to cover both code paths.\n    """\n    enabled = request.param\n    monkeypatch.setenv(MLFLOW_ENABLE_WORKSPACES.name, "true" if enabled else "false")\n    if enabled:\n        with WorkspaceContext(DEFAULT_WORKSPACE_NAME):\n            yield enabled\n    else:\n        yield enabled\n\n\n@job(name="basic_job_fun", max_workers=1)\ndef basic_job_fun(x, y, sleep_secs=0):\n    if sleep_secs > 0:\n        time.sleep(sleep_secs)\n    return x + y\n\n\ndef test_basic_job(monkeypatch, tmp_path):\n    with _setup_job_runner(\n        monkeypatch,\n        tmp_path,\n        supported_job_functions=["tests.server.jobs.test_jobs.basic_job_fun"],\n        allowed_job_names=["basic_job_fun"],\n    ):\n        submitted_job = submit_job(basic_job_fun, {"x": 3, "y": 4})\n        wait_job_finalize(submitted_job.job_id)\n        job = get_job(submitted_job.job_id)\n        assert job.job_id == submitted_job.job_id\n        assert job.job_name == "basic_job_fun"\n        assert job.params == \'{"x": 3, "y": 4}\'\n        assert job.timeout is None\n        assert job.result == "7"\n        assert job.parsed_result == 7\n        assert job.status == JobStatus.SUCCEEDED\n        assert job.retry_count == 0\n\n\n@job(name="json_in_out_fun", max_workers=1)\ndef json_in_out_fun(data):\n    x = data["x"]\n    y = data["y"]\n    return {"res": x + y}\n\n\ndef test_job_json_input_output(monkeypatch, tmp_path):\n    with _setup_job_runner(\n        monkeypatch,\n        tmp_path,\n        supported_job_functions=["tests.server.jobs.test_jobs.json_in_out_fun"],\n        allowed_job_names=["json_in_out_fun"],\n    ):\n        submitted_job = submit_job(json_in_out_fun, {"data": {"x": 3, "y": 4}})\n        wait_job_finalize(submitted_job.job_id)\n        job = get_job(submitted_job.job_id)\n        assert job.job_id == submitted_job.job_id\n        assert job.job_name == "json_in_out_fun"\n        assert job.params == \'{"data": {"x": 3, "y": 4}}\'\n        assert job.result == \'{"res": 7}\'\n        assert job.parsed_result == {"res": 7}\n        assert job.status == JobStatus.SUCCEEDED\n        assert job.retry_count == 0\n\n\n@job(name="err_fun", max_workers=1)\ndef err_fun(data):\n    raise RuntimeError()\n\n\ndef test_error_job(monkeypatch, tmp_path):\n    with _setup_job_runner(\n        monkeypatch,\n        tmp_path,\n        supported_job_functions=["tests.server.jobs.test_jobs.err_fun"],\n        allowed_job_names=["err_fun"],\n    ):\n        submitted_job = submit_job(err_fun, {"data": None})\n        wait_job_finalize(submitted_job.job_id)\n        job = get_job(submitted_job.job_id)\n\n        # check database record correctness.\n        assert job.job_id == submitted_job.job_id\n        assert job.job_name == "err_fun"\n        assert job.params == \'{"data": null}\'\n        assert job.result.startswith("RuntimeError()")\n        assert job.status == JobStatus.FAILED\n        assert job.retry_count == 0\n\n\ndef assert_job_result(job_id, expected_status, expected_result):\n    job = get_job(job_id)\n    assert job.status == expected_status\n    assert job.parsed_result == expected_result\n\n\ndef test_job_resume_on_job_runner_restart(monkeypatch, tmp_path):\n    with _setup_job_runner(\n        monkeypatch,\n        tmp_path,\n        supported_job_functions=["tests.server.jobs.test_jobs.basic_job_fun"],\n        allowed_job_names=["basic_job_fun"],\n    ) as job_runner_proc:\n        job1_id = submit_job(basic_job_fun, {"x": 3, "y": 4, "sleep_secs": 0}).job_id\n        job2_id = submit_job(basic_job_fun, {"x": 5, "y": 6, "sleep_secs": 2}).job_id\n        job3_id = submit_job(basic_job_fun, {"x": 7, "y": 8, "sleep_secs": 0}).job_id\n        wait_job_finalize(job1_id)\n        job_runner_proc.kill()\n        job_runner_proc.wait()  # ensure the job runner process is killed.\n\n        # assert that job1 has done, job2 is running, and job3 is pending.\n        assert_job_result(job1_id, JobStatus.SUCCEEDED, 7)\n        assert_job_result(job2_id, JobStatus.RUNNING, None)\n        assert_job_result(job3_id, JobStatus.PENDING, None)\n\n        # restart the job runner, and verify it resumes unfinished jobs (job2 and job3)\n        with _launch_job_runner_for_test():\n            wait_job_finalize(job2_id)\n            wait_job_finalize(job3_id)\n            # assert all jobs are done.\n            assert_job_result(job1_id, JobStatus.SUCCEEDED, 7)\n            assert_job_result(job2_id, JobStatus.SUCCEEDED, 11)\n            assert_job_result(job3_id, JobStatus.SUCCEEDED, 15)\n\n\ndef test_job_resume_on_new_job_runner(monkeypatch, tmp_path):\n    db_tmp_path = tmp_path / "db"\n    db_tmp_path.mkdir()\n    runner1_tmp_path = tmp_path / "runner1"\n    runner1_tmp_path.mkdir()\n    runner2_tmp_path = tmp_path / "runner2"\n    runner2_tmp_path.mkdir()\n\n    backend_store_uri = f"sqlite:///{db_tmp_path / \'mlflow.db\'!s}"\n\n    with _setup_job_runner(\n        monkeypatch,\n        runner1_tmp_path,\n        supported_job_functions=["tests.server.jobs.test_jobs.basic_job_fun"],\n        allowed_job_names=["basic_job_fun"],\n        backend_store_uri=backend_store_uri,\n    ) as job_runner_proc:\n        job1_id = submit_job(basic_job_fun, {"x": 3, "y": 4, "sleep_secs": 0}).job_id\n        job2_id = submit_job(basic_job_fun, {"x": 5, "y": 6, "sleep_secs": 2}).job_id\n        job3_id = submit_job(basic_job_fun, {"x": 7, "y": 8, "sleep_secs": 0}).job_id\n        wait_job_finalize(job1_id)\n\n        # assert that job1 has done, job2 is running, and job3 is pending.\n        assert_job_result(job1_id, JobStatus.SUCCEEDED, 7)\n        assert_job_result(job2_id, JobStatus.RUNNING, None)\n        assert_job_result(job3_id, JobStatus.PENDING, None)\n\n    # ensure the job runner process is killed.\n    job_runner_proc.wait()\n\n    with _setup_job_runner(\n        monkeypatch,\n        runner2_tmp_path,\n        supported_job_functions=["tests.server.jobs.test_jobs.basic_job_fun"],\n        allowed_job_names=["basic_job_fun"],\n        backend_store_uri=backend_store_uri,\n    ):\n        wait_job_finalize(job2_id)\n        wait_job_finalize(job3_id)\n        # assert all jobs are done.\n        assert_job_result(job1_id, JobStatus.SUCCEEDED, 7)\n        assert_job_result(job2_id, JobStatus.SUCCEEDED, 11)\n        assert_job_result(job3_id, JobStatus.SUCCEEDED, 15)\n\n\n@job(name="job_fun_parallelism2", max_workers=2)\ndef job_fun_parallelism2(x, y, sleep_secs=0):\n    if sleep_secs > 0:\n        time.sleep(sleep_secs)\n    return x + y\n\n\n@job(name="job_fun_parallelism3", max_workers=3)\ndef job_fun_parallelism3(x, y, sleep_secs=0):\n    if sleep_secs > 0:\n        time.sleep(sleep_secs)\n    return x + y\n\n\ndef test_job_queue_parallelism(monkeypatch, tmp_path):\n    with _setup_job_runner(\n        monkeypatch,\n        tmp_path,\n        supported_job_functions=[\n            "tests.server.jobs.test_jobs.job_fun_parallelism2",\n            "tests.server.jobs.test_jobs.job_fun_parallelism3",\n        ],\n        allowed_job_names=["job_fun_parallelism2", "job_fun_parallelism3"],\n    ):\n        for x in range(4):\n            submit_job(job_fun_parallelism2, {"x": x, "y": 1, "sleep_secs": 2})\n\n        for x in range(6):\n            submit_job(job_fun_parallelism3, {"x": x, "y": 1, "sleep_secs": 2})\n\n        job_store = _get_job_store()\n        p2_peak_parallelism = 0\n        p3_peak_parallelism = 0\n\n        deadline = time.time() + 60\n        while time.time() < deadline:\n            p2_parallelism = 0\n            p3_parallelism = 0\n\n            p2_succeeded_count = 0\n            p3_succeeded_count = 0\n\n            jobs = list(job_store.list_jobs())\n            for job in jobs:\n                if job.job_name == "job_fun_parallelism2":\n                    if job.status == JobStatus.RUNNING:\n                        p2_parallelism += 1\n                    elif job.status == JobStatus.SUCCEEDED:\n                        p2_succeeded_count += 1\n                elif job.job_name == "job_fun_parallelism3":\n                    if job.status == JobStatus.RUNNING:\n                        p3_parallelism += 1\n                    elif job.status == JobStatus.SUCCEEDED:\n                        p3_succeeded_count += 1\n\n            if p2_parallelism > p2_peak_parallelism:\n                p2_peak_parallelism = p2_parallelism\n\n            if p3_parallelism > p3_peak_parallelism:\n                p3_peak_parallelism = p3_parallelism\n\n            if p2_succeeded_count + p3_succeeded_count == 10:\n                break\n            time.sleep(1)\n        else:\n            assert False, "Submitted Jobs do not succeed within timeout."\n\n        assert p2_peak_parallelism == 2\n        assert p3_peak_parallelism == 3\n\n\n@job(name="transient_err_fun_always_fail", max_workers=1)\ndef transient_err_fun_always_fail():\n    raise TransientError(RuntimeError("test transient error."))\n\n\n@job(name="transient_err_fun_fail_then_succeed", max_workers=1)\ndef transient_err_fun_fail_then_succeed(counter_file: str):\n    counter_path = Path(counter_file)\n\n    try:\n        current = int(counter_path.read_text()) if counter_path.exists() else 0\n    except (ValueError, FileNotFoundError):\n        current = 0\n\n    current += 1\n    counter_path.write_text(str(current))\n\n    if current >= 2:\n        return 100\n    raise TransientError(RuntimeError("test transient error."))\n\n\n@job(\n    name="transient_err_fun2_fail_then_succeed",\n    max_workers=1,\n    transient_error_classes=[TimeoutError],\n)\ndef transient_err_fun2_fail_then_succeed(counter_file: str):\n    counter_path = Path(counter_file)\n\n    try:\n        current = int(counter_path.read_text()) if counter_path.exists() else 0\n    except (ValueError, FileNotFoundError):\n        current = 0\n\n    current += 1\n    counter_path.write_text(str(current))\n\n    if current >= 2:\n        return 100\n    raise TimeoutError("test transient timeout error.")\n\n\ndef test_job_retry_on_transient_error(monkeypatch, tmp_path):\n    monkeypatch.setenv("MLFLOW_SERVER_JOB_TRANSIENT_ERROR_RETRY_BASE_DELAY", "1")\n    monkeypatch.setenv("MLFLOW_SERVER_JOB_TRANSIENT_ERROR_MAX_RETRIES", "2")\n    with _setup_job_runner(\n        monkeypatch,\n        tmp_path,\n        supported_job_functions=[\n            "tests.server.jobs.test_jobs.transient_err_fun_always_fail",\n            "tests.server.jobs.test_jobs.transient_err_fun_fail_then_succeed",\n            "tests.server.jobs.test_jobs.transient_err_fun2_fail_then_succeed",\n        ],\n        allowed_job_names=[\n            "transient_err_fun_always_fail",\n            "transient_err_fun_fail_then_succeed",\n            "transient_err_fun2_fail_then_succeed",\n        ],\n    ):\n        store = _get_job_store()\n\n        # Test 1: Job that always fails should exhaust retries and fail\n        job1_id = submit_job(transient_err_fun_always_fail, {}).job_id\n        wait_job_finalize(job1_id)\n        assert_job_result(job1_id, JobStatus.FAILED, "RuntimeError(\'test transient error.\')")\n        job1 = store.get_job(job1_id)\n        assert job1.status == JobStatus.FAILED\n        assert job1.result == "RuntimeError(\'test transient error.\')"\n        assert job1.retry_count == 2\n\n        # Test 2: Job that fails once then succeeds should succeed with retry_count=1\n        job2_counter = tmp_path / "job2_counter.txt"\n        job2_id = submit_job(\n            transient_err_fun_fail_then_succeed, {"counter_file": str(job2_counter)}\n        ).job_id\n        wait_job_finalize(job2_id)\n        assert_job_result(job2_id, JobStatus.SUCCEEDED, 100)\n        job2 = store.get_job(job2_id)\n        assert job2.status == JobStatus.SUCCEEDED\n        assert job2.result == "100"\n        assert job2.retry_count == 1\n\n        # Test 3: Same as test 2 but with custom transient_error_classes\n        job3_counter = tmp_path / "job3_counter.txt"\n        job3_id = submit_job(\n            transient_err_fun2_fail_then_succeed, {"counter_file": str(job3_counter)}\n        ).job_id\n        wait_job_finalize(job3_id)\n        assert_job_result(job3_id, JobStatus.SUCCEEDED, 100)\n        job3 = store.get_job(job3_id)\n        assert job3.status == JobStatus.SUCCEEDED\n        assert job3.result == "100"\n        assert job3.retry_count == 1\n\n\n# `submit_job` API is designed to be called inside MLflow server handler,\n# MLflow server handler might be executed in multiple MLflow server workers\n# so that we need a test to cover the case that executes `submit_job` in\n# multi-processes case.\ndef test_submit_jobs_from_multi_processes(monkeypatch, tmp_path):\n    context = multiprocessing.get_context("spawn")\n    with (\n        _setup_job_runner(\n            monkeypatch,\n            tmp_path,\n            supported_job_functions=["tests.server.jobs.test_jobs.basic_job_fun"],\n            allowed_job_names=["basic_job_fun"],\n        ),\n        context.Pool(2) as pool,\n    ):\n        job_id = submit_job(basic_job_fun, {"x": 1, "y": 1, "sleep_secs": 0}).job_id\n        wait_job_finalize(job_id)\n\n        async_res_list = [\n            pool.apply_async(\n                submit_job,\n                args=(basic_job_fun,),\n                kwds={"params": {"x": x, "y": 1, "sleep_secs": 2}},\n            )\n            for x in range(2)\n        ]\n        job_ids = [async_res.get().job_id for async_res in async_res_list]\n        for job_id in job_ids:\n            wait_job_finalize(job_id)\n        for x in range(2):\n            assert_job_result(job_ids[x], JobStatus.SUCCEEDED, x + 1)\n\n\n@job(name="sleep_fun", max_workers=1)\ndef sleep_fun(sleep_secs, tmp_dir):\n    (Path(tmp_dir) / "pid").write_text(str(os.getpid()))\n    time.sleep(sleep_secs)\n\n\ndef test_job_timeout(monkeypatch, tmp_path):\n    with _setup_job_runner(\n        monkeypatch,\n        tmp_path,\n        supported_job_functions=["tests.server.jobs.test_jobs.sleep_fun"],\n        allowed_job_names=["sleep_fun"],\n    ):\n        job_tmp_path = tmp_path / "job"\n        job_tmp_path.mkdir()\n\n        # warm up\n        job_id = submit_job(sleep_fun, {"sleep_secs": 0, "tmp_dir": str(job_tmp_path)}).job_id\n        wait_job_finalize(job_id)\n\n        job_id = submit_job(\n            sleep_fun, {"sleep_secs": 10, "tmp_dir": str(job_tmp_path)}, timeout=3\n        ).job_id\n        wait_job_finalize(job_id)\n        pid = int((job_tmp_path / "pid").read_text())\n        wait_for_process_exit(pid)\n\n        assert_job_result(job_id, JobStatus.TIMEOUT, None)\n\n        store = _get_job_store()\n        job = store.get_job(job_id)\n\n        # check database record correctness.\n        assert job.job_id == job_id\n        assert job.job_name == "sleep_fun"\n        assert job.timeout == 3.0\n        assert job.result is None\n        assert job.status == JobStatus.TIMEOUT\n        assert job.retry_count == 0\n\n\ndef test_list_job_pagination(monkeypatch, tmp_path):\n    import mlflow.store.jobs.sqlalchemy_store\n\n    monkeypatch.setattr(mlflow.store.jobs.sqlalchemy_store, "_LIST_JOB_PAGE_SIZE", 3)\n    with _setup_job_runner(\n        monkeypatch,\n        tmp_path,\n        supported_job_functions=["tests.server.jobs.test_jobs.basic_job_fun"],\n        allowed_job_names=["basic_job_fun"],\n    ):\n        job_ids = [submit_job(basic_job_fun, {"x": x, "y": 4}).job_id for x in range(10)]\n\n        listed_jobs = _get_job_store().list_jobs()\n        assert [job.job_id for job in listed_jobs] == job_ids\n\n\ndef bad_job_function() -> None:\n    return\n\n\ndef test_job_function_without_decorator(monkeypatch, tmp_path):\n    with _setup_job_runner(\n        monkeypatch,\n        tmp_path,\n        supported_job_functions=["tests.server.jobs.test_jobs.bad_job_function"],\n        allowed_job_names=["bad_job_function"],\n    ):\n        with pytest.raises(\n            MlflowException,\n            match="The job function tests.server.jobs.test_jobs.bad_job_function is not decorated",\n        ):\n            submit_job(bad_job_function, params={})\n\n\n@job(name="job_use_process", max_workers=1)\ndef job_use_process(tmp_dir):\n    (Path(tmp_dir) / str(os.getpid())).write_text("")\n\n\ndef test_job_use_process(monkeypatch, tmp_path):\n    with _setup_job_runner(\n        monkeypatch,\n        tmp_path,\n        supported_job_functions=["tests.server.jobs.test_jobs.job_use_process"],\n        allowed_job_names=["job_use_process"],\n    ):\n        job_tmp_path = tmp_path / "job"\n        job_tmp_path.mkdir()\n\n        job_id1 = submit_job(job_use_process, {"tmp_dir": str(job_tmp_path)}).job_id\n        job_id2 = submit_job(job_use_process, {"tmp_dir": str(job_tmp_path)}).job_id\n        wait_job_finalize(job_id1)\n        wait_job_finalize(job_id2)\n        assert len(os.listdir(str(job_tmp_path))) == 2\n\n\ndef test_submit_job_bad_call(monkeypatch, tmp_path):\n    with _setup_job_runner(\n        monkeypatch,\n        tmp_path,\n        supported_job_functions=["tests.server.jobs.test_jobs.basic_job_fun"],\n        allowed_job_names=["basic_job_fun"],\n    ):\n        with pytest.raises(\n            MlflowException,\n            match="When calling \'submit_job\', the \'params\' argument must be a dict.",\n        ):\n            submit_job(basic_job_fun, params=None)\n\n\n@job(\n    name="python_env_checker",\n    max_workers=1,\n    python_version="3.11.9",\n    pip_requirements=["openai==1.108.2", "pytest<9"],\n)\ndef check_python_env_fn():\n    import openai\n\n    from mlflow.server.jobs.utils import MLFLOW_SERVER_JOB_NAME_ENV_VAR\n    from mlflow.utils import PYTHON_VERSION\n\n    assert PYTHON_VERSION == "3.11.9"\n    assert openai.__version__ == "1.108.2"\n\n    assert os.environ.get(MLFLOW_SERVER_JOB_NAME_ENV_VAR) == "python_env_checker"\n    assert (\n        os.environ.get("_MLFLOW_SERVER_JOB_FUNCTION_FULLNAME")\n        == "tests.server.jobs.test_jobs.check_python_env_fn"\n    )\n\n\ndef test_job_with_python_env(monkeypatch, tmp_path):\n    monkeypatch.setenv("MLFLOW_HOME", _get_mlflow_repo_home())\n\n    with _setup_job_runner(\n        monkeypatch,\n        tmp_path,\n        supported_job_functions=["tests.server.jobs.test_jobs.check_python_env_fn"],\n        allowed_job_names=["python_env_checker"],\n    ):\n        job_id = submit_job(check_python_env_fn, params={}).job_id\n        wait_job_finalize(job_id, timeout=600)\n        job = get_job(job_id)\n        assert job.status == JobStatus.SUCCEEDED\n\n\ndef test_start_job_is_atomic(tmp_path: Path, workspaces_enabled):\n    backend_store_uri = f"sqlite:///{tmp_path / \'test.db\'}"\n    store_cls = WorkspaceAwareSqlAlchemyJobStore if workspaces_enabled else SqlAlchemyJobStore\n    store = store_cls(backend_store_uri)\n\n    job = store.create_job("test.function", \'{"param": "value"}\')\n    assert job.status == JobStatus.PENDING\n\n    results = []\n\n    def try_start_job() -> str:\n        try:\n            store.start_job(job.job_id)\n            return "success"\n        except MlflowException:\n            return "failed"\n\n    with concurrent.futures.ThreadPoolExecutor(max_workers=5) as executor:\n        futures = [executor.submit(try_start_job) for _ in range(5)]\n        results = [f.result() for f in concurrent.futures.as_completed(futures)]\n\n    assert results.count("success") == 1\n    assert results.count("failed") == 4\n\n    final_job = store.get_job(job.job_id)\n    assert final_job.status == JobStatus.RUNNING\n\n\ndef test_cancel_job(monkeypatch, tmp_path: Path):\n    with _setup_job_runner(\n        monkeypatch,\n        tmp_path,\n        supported_job_functions=["tests.server.jobs.test_jobs.sleep_fun"],\n        allowed_job_names=["sleep_fun"],\n    ):\n        job_tmp_path = tmp_path / "job"\n        job_tmp_path.mkdir()\n\n        job_id = submit_job(sleep_fun, {"sleep_secs": 120, "tmp_dir": str(job_tmp_path)}).job_id\n\n        while not (job_tmp_path / "pid").exists():\n            time.sleep(1)  # wait for job process starting\n\n        cancel_job(job_id)\n\n        pid = int((job_tmp_path / "pid").read_text())\n        wait_for_process_exit(pid, timeout=10)\n\n        assert get_job(job_id).status == JobStatus.CANCELED\n\n\ndef test_delete_jobs_only_deletes_finalized(tmp_path: Path):\n    backend_store_uri = f"sqlite:///{tmp_path / \'test.db\'}"\n    store = SqlAlchemyJobStore(backend_store_uri)\n\n    pending_job = store.create_job("pending_job", "{}")\n    assert pending_job.status == JobStatus.PENDING\n\n    running_job = store.create_job("running_job", "{}")\n    store.start_job(running_job.job_id)\n    running_job = store.get_job(running_job.job_id)\n    assert running_job.status == JobStatus.RUNNING\n\n    succeeded_job = store.create_job("succeeded_job", "{}")\n    store.start_job(succeeded_job.job_id)\n    store.finish_job(succeeded_job.job_id, "result")\n    succeeded_job = store.get_job(succeeded_job.job_id)\n    assert succeeded_job.status == JobStatus.SUCCEEDED\n\n    failed_job = store.create_job("failed_job", "{}")\n    store.start_job(failed_job.job_id)\n    store.fail_job(failed_job.job_id, "error")\n    failed_job = store.get_job(failed_job.job_id)\n    assert failed_job.status == JobStatus.FAILED\n\n    timeout_job = store.create_job("timeout_job", "{}")\n    store.start_job(timeout_job.job_id)\n    store.mark_job_timed_out(timeout_job.job_id)\n    timeout_job = store.get_job(timeout_job.job_id)\n    assert timeout_job.status == JobStatus.TIMEOUT\n\n    canceled_job = store.create_job("canceled_job", "{}")\n    store.cancel_job(canceled_job.job_id)\n    canceled_job = store.get_job(canceled_job.job_id)\n    assert canceled_job.status == JobStatus.CANCELED\n\n    deleted_ids = store.delete_jobs()\n\n    # Should only delete finalized jobs\n    assert len(deleted_ids) == 4\n    assert succeeded_job.job_id in deleted_ids\n    assert failed_job.job_id in deleted_ids\n    assert timeout_job.job_id in deleted_ids\n    assert canceled_job.job_id in deleted_ids\n\n    # Non-finalized jobs should still exist\n    assert store.get_job(pending_job.job_id).status == JobStatus.PENDING\n    assert store.get_job(running_job.job_id).status == JobStatus.RUNNING\n\n    # Finalized jobs should be deleted\n    with pytest.raises(MlflowException, match=r"Job .+ not found"):\n        store.get_job(succeeded_job.job_id)\n    with pytest.raises(MlflowException, match=r"Job .+ not found"):\n        store.get_job(failed_job.job_id)\n    with pytest.raises(MlflowException, match=r"Job .+ not found"):\n        store.get_job(timeout_job.job_id)\n    with pytest.raises(MlflowException, match=r"Job .+ not found"):\n        store.get_job(canceled_job.job_id)\n\n\ndef test_delete_jobs_with_job_ids_filter(tmp_path: Path):\n    backend_store_uri = f"sqlite:///{tmp_path / \'test.db\'}"\n    store = SqlAlchemyJobStore(backend_store_uri)\n\n    job1 = store.create_job("job1", "{}")\n    store.start_job(job1.job_id)\n    store.finish_job(job1.job_id, "result")\n\n    job2 = store.create_job("job2", "{}")\n    store.start_job(job2.job_id)\n    store.finish_job(job2.job_id, "result")\n\n    job3 = store.create_job("job3", "{}")\n    store.start_job(job3.job_id)\n    store.finish_job(job3.job_id, "result")\n\n    deleted_ids = store.delete_jobs(job_ids=[job1.job_id, job2.job_id])\n\n    assert len(deleted_ids) == 2\n    assert job1.job_id in deleted_ids\n    assert job2.job_id in deleted_ids\n\n    assert store.get_job(job3.job_id).status == JobStatus.SUCCEEDED\n\n    with pytest.raises(MlflowException, match=r"Job .+ not found"):\n        store.get_job(job1.job_id)\n    with pytest.raises(MlflowException, match=r"Job .+ not found"):\n        store.get_job(job2.job_id)\n\n\ndef test_delete_jobs_skips_non_finalized_even_with_job_ids(tmp_path: Path):\n    backend_store_uri = f"sqlite:///{tmp_path / \'test.db\'}"\n    store = SqlAlchemyJobStore(backend_store_uri)\n\n    pending_job = store.create_job("pending_job", "{}")\n    assert pending_job.status == JobStatus.PENDING\n\n    succeeded_job = store.create_job("succeeded_job", "{}")\n    store.start_job(succeeded_job.job_id)\n    store.finish_job(succeeded_job.job_id, "result")\n    assert store.get_job(succeeded_job.job_id).status == JobStatus.SUCCEEDED\n\n    deleted_ids = store.delete_jobs(job_ids=[pending_job.job_id, succeeded_job.job_id])\n\n    assert len(deleted_ids) == 1\n    assert succeeded_job.job_id in deleted_ids\n\n    assert store.get_job(pending_job.job_id).status == JobStatus.PENDING\n\n    with pytest.raises(MlflowException, match=r"Job .+ not found"):\n        store.get_job(succeeded_job.job_id)\n\n\n@job(name="env_var_reader_fun", max_workers=1)\ndef env_var_reader_fun(env_var_name: str):\n    return os.environ.get(env_var_name)\n\n\n@job(name="multiple_env_vars_fun", max_workers=1)\ndef multiple_env_vars_fun(env_var_names: list[str]):\n    return {name: os.environ.get(name) for name in env_var_names}\n\n\n@job(name="exclusive_sleep_fun", max_workers=2, exclusive=True)\ndef exclusive_sleep_fun(sleep_secs: int, experiment_id: str, tmp_dir: str):\n    pid_file = Path(tmp_dir) / f"pid_{experiment_id}"\n    pid_file.write_text(str(os.getpid()))\n    time.sleep(sleep_secs)\n    return experiment_id\n\n\ndef test_exclusive_job_skips_duplicate(monkeypatch, tmp_path: Path):\n    with _setup_job_runner(\n        monkeypatch,\n        tmp_path,\n        supported_job_functions=["tests.server.jobs.test_jobs.exclusive_sleep_fun"],\n        allowed_job_names=["exclusive_sleep_fun"],\n    ):\n        job_tmp_path = tmp_path / "job"\n        job_tmp_path.mkdir()\n\n        params = {"sleep_secs": 2, "experiment_id": "exp1", "tmp_dir": str(job_tmp_path)}\n\n        job1_id = submit_job(exclusive_sleep_fun, params).job_id\n        job2_id = submit_job(exclusive_sleep_fun, params).job_id\n\n        wait_job_finalize(job1_id)\n        wait_job_finalize(job2_id)\n\n        job1 = get_job(job1_id)\n        job2 = get_job(job2_id)\n\n        # One job succeeds, the other is canceled (skipped due to exclusive lock)\n        statuses = {job1.status, job2.status}\n        assert JobStatus.SUCCEEDED in statuses\n        assert JobStatus.CANCELED in statuses\n\n\ndef test_exclusive_job_allows_different_params(monkeypatch, tmp_path: Path):\n    with _setup_job_runner(\n        monkeypatch,\n        tmp_path,\n        supported_job_functions=["tests.server.jobs.test_jobs.exclusive_sleep_fun"],\n        allowed_job_names=["exclusive_sleep_fun"],\n    ):\n        job_tmp_path = tmp_path / "job"\n        job_tmp_path.mkdir()\n\n        job1_id = submit_job(\n            exclusive_sleep_fun,\n            {"sleep_secs": 2, "experiment_id": "exp1", "tmp_dir": str(job_tmp_path)},\n        ).job_id\n        job2_id = submit_job(\n            exclusive_sleep_fun,\n            {"sleep_secs": 2, "experiment_id": "exp2", "tmp_dir": str(job_tmp_path)},\n        ).job_id\n\n        wait_job_finalize(job1_id)\n        wait_job_finalize(job2_id)\n\n        # Both jobs should succeed since they have different params\n        assert get_job(job1_id).status == JobStatus.SUCCEEDED\n        assert get_job(job2_id).status == JobStatus.SUCCEEDED\n\n\ndef test_submit_job_with_extra_envs(monkeypatch, tmp_path):\n    with _setup_job_runner(\n        monkeypatch,\n        tmp_path,\n        supported_job_functions=["tests.server.jobs.test_jobs.multiple_env_vars_fun"],\n        allowed_job_names=["multiple_env_vars_fun"],\n    ):\n        job_id = submit_job(\n            multiple_env_vars_fun,\n            {"env_var_names": ["VAR1", "VAR2", "VAR3"]},\n            extra_envs={"VAR1": "value1", "VAR2": "value2", "VAR3": "value3"},\n        ).job_id\n        wait_job_finalize(job_id)\n\n        job = get_job(job_id)\n        assert job.status == JobStatus.SUCCEEDED\n        assert job.parsed_result == {"VAR1": "value1", "VAR2": "value2", "VAR3": "value3"}\n    for name in ["VAR1", "VAR2", "VAR3"]:\n        assert os.environ.get(name) is None\n\n\ndef test_submit_job_without_extra_envs(monkeypatch, tmp_path):\n    with _setup_job_runner(\n        monkeypatch,\n        tmp_path,\n        supported_job_functions=["tests.server.jobs.test_jobs.env_var_reader_fun"],\n        allowed_job_names=["env_var_reader_fun"],\n    ):\n        job_id = submit_job(\n            env_var_reader_fun,\n            {"env_var_name": "NONEXISTENT_VAR"},\n        ).job_id\n        wait_job_finalize(job_id)\n\n        job = get_job(job_id)\n        assert job.status == JobStatus.SUCCEEDED\n        assert job.parsed_result is None\n\n\n@job(name="workspace_env_checker", max_workers=1)\ndef workspace_env_checker():\n    return MLFLOW_WORKSPACE.get()\n\n\ndef test_submit_job_workspace_propagation(monkeypatch, tmp_path, workspaces_enabled):\n    expected_workspace = DEFAULT_WORKSPACE_NAME if workspaces_enabled else None\n\n    with _setup_job_runner(\n        monkeypatch,\n        tmp_path,\n        supported_job_functions=["tests.server.jobs.test_jobs.workspace_env_checker"],\n        allowed_job_names=["workspace_env_checker"],\n    ):\n        submitted_job = submit_job(workspace_env_checker, {})\n        wait_job_finalize(submitted_job.job_id)\n\n        job = get_job(submitted_job.job_id)\n        assert job.status == JobStatus.SUCCEEDED\n        assert job.parsed_result == expected_workspace\n',
        }
